from flask import Flask, request, jsonify
from selenium import webdriver
from selenium.webdriver.chrome.service import Service
from selenium.webdriver.chrome.options import Options
from webdriver_manager.chrome import ChromeDriverManager
import boto3
import os
import uuid
from PIL import Image
from io import BytesIO

app = Flask(__name__)

s3_client = boto3.client('s3')
BUCKET_NAME = 'your-s3-bucket-name'

chrome_options = Options()
chrome_options.add_argument("--headless")
chrome_options.add_argument("--no-sandbox")
chrome_options.add_argument("--disable-dev-shm-usage")

def capture_screenshot(url):
    driver = webdriver.Chrome(service=Service(ChromeDriverManager().install()), options=chrome_options)
    driver.get(url)
    driver.set_window_size(1280, 800)
    screenshot = driver.get_screenshot_as_png()
    driver.quit()
    return screenshot

def upload_to_s3(screenshot):
    image_id = str(uuid.uuid4())
    image_path = f"screenshots/{image_id}.png"
    s3_client.put_object(Bucket=BUCKET_NAME, Key=image_path, Body=screenshot, ContentType='image/png')
    return image_path

@app.route('/screenshot', methods=['POST'])
def screenshot_service():
    data = request.json
    url = data.get('url')
    if not url:
        return jsonify({"error": "URL is required"}), 400

    screenshot = capture_screenshot(url)
    image_path = upload_to_s3(screenshot)

    return jsonify({"image_url": f"https://{BUCKET_NAME}.s3.amazonaws.com/{image_path}"}), 200

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000)